import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useDoctorRegistration } from '../../../context/doctorRegistrationContext';
import PublicLayout from '../../../components/layouts/publiclayout';
import '../../../styles/doctor/register/DoctorRegisterStep1.css';

const DoctorRegisterStep1: React.FC = () => {
    const navigate = useNavigate();
    const { updatePersonalData } = useDoctorRegistration();
    const [isLoading, setIsLoading] = useState(false);

    const [formData, setFormData] = useState({
        fullName: '',
        email: '',
        mobile: '',
        dob: '',
        gender: Gender ,
        password: '',
        confirmPassword: '',
        agreeTerms: false
    });

    const [errors, setErrors] = useState<Record<string, string>>({});
    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);

    /* =========================
       LOAD SAVED DATA
    ========================= */
    useEffect(() => {
        const saved = localStorage.getItem('doctorPersonalData');
        if (saved) {
            try {
                setFormData(JSON.parse(saved));
            } catch {
                /* ignore invalid data */
            }
        }
    }, []);

    /* =========================
       DOB LIMITS
    ========================= */
    useEffect(() => {
        const today = new Date();
        const maxDate = new Date(today.getFullYear() - 21, today.getMonth(), today.getDate());
        const minDate = new Date(today.getFullYear() - 80, today.getMonth(), today.getDate());
        const dobInput = document.getElementById('dob') as HTMLInputElement | null;

        if (dobInput) {
            dobInput.max = maxDate.toISOString().split('T')[0];
            dobInput.min = minDate.toISOString().split('T')[0];
        }
    }, []);

    /* =========================
       HANDLERS
    ========================= */
    const formatMobileNumber = (value: string) =>
        value.replace(/\D/g, '').slice(0, 10);

    const handleChange = (
        e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>
    ) => {
        const { name, value, type } = e.target as HTMLInputElement;

        if (type === 'checkbox') {
            setFormData(prev => ({ ...prev, [name]: (e.target as HTMLInputElement).checked }));
            setErrors(prev => ({ ...prev, [name]: '' }));
            return;
        }

        if (name === 'mobile') {
            setFormData(prev => ({ ...prev, mobile: formatMobileNumber(value) }));
            setErrors(prev => ({ ...prev, mobile: '' }));
            return;
        }

        setFormData(prev => ({ ...prev, [name]: value }));
        setErrors(prev => ({ ...prev, [name]: '' }));
    };

    /* =========================
       VALIDATION
    ========================= */
    const validate = () => {
        const newErrors: Record<string, string> = {};
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        const passwordRegex =
            /^(?=.*[A-Za-z])(?=.*\d)(?=.*[@$!%*#?&])[A-Za-z\d@$!%*#?&]{8,}$/;

        if (!formData.fullName || formData.fullName.trim().length < 3)
            newErrors.fullName = 'Full name is required';

        if (!formData.email || !emailRegex.test(formData.email))
            newErrors.email = 'Valid professional email required';

        if (!/^\d{10}$/.test(formData.mobile))
            newErrors.mobile = 'Enter a valid 10-digit mobile number';

        if (!formData.dob) newErrors.dob = 'Date of birth is required';
        if (!formData.gender) newErrors.gender = 'Gender is required';

        if (!passwordRegex.test(formData.password))
            newErrors.password =
                'Password must be 8+ chars with letters, numbers and a special char';

        if (formData.password !== formData.confirmPassword)
            newErrors.confirmPassword = 'Passwords must match';

        if (!formData.agreeTerms)
            newErrors.agreeTerms = 'You must agree to terms';

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    /* =========================
       SUBMIT
    ========================= */
    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!validate()) return;

        setIsLoading(true);
        try {
            const personalData = {
                ...formData,
                password: btoa(formData.password),
                userType: 'doctor'
            };

            localStorage.setItem('doctorPersonalData', JSON.stringify(personalData));
            updatePersonalData(personalData);

            await new Promise(res => setTimeout(res, 800));
            navigate('/doctor/register/step2');
        } finally {
            setIsLoading(false);
        }
    };

    /* =========================
       RENDER
    ========================= */
    return (
        <PublicLayout>
            <div className="content-container">
                <div className="registration-wrapper">

                    {/* STEPS */}
                    <div className="steps">
                        <div className="step active">
                            <div className="step-number">1</div>
                            <div className="step-label">Personal Info</div>
                        </div>
                        <div className="step">
                            <div className="step-number">2</div>
                            <div className="step-label">Professional Info</div>
                        </div>
                        <div className="step">
                            <div className="step-number">3</div>
                            <div className="step-label">Verification</div>
                        </div>
                    </div>

                    {/* FORM */}
                    <div className="form-container">
                        <div className="form-header">
                            <h1>Doctor Registration</h1>
                            <p>Step 1: Fill in your personal information</p>
                        </div>

                        <form onSubmit={handleSubmit}>
                            {/* --- ALL YOUR FORM FIELDS REMAIN UNCHANGED --- */}

                            <button type="submit" className="btn btn-primary" disabled={isLoading}>
                                {isLoading ? 'Processing...' : 'Continue to Professional Information'}
                            </button>
                        </form>

                        <div className="login-link">
                            Already have a doctor account?
                            <Link to="/doctor/login"> Sign In</Link>
                        </div>
                    </div>

                </div>
            </div>
        </PublicLayout>
    );
};

export default DoctorRegisterStep1;
